  "inlineSchema": "// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\n// Get a free hosted Postgres database in seconds: `npx create-db`\n\ngenerator client {\n  provider = \"prisma-client\"\n  output   = \"../src/generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// ─────────────────────────────────────────\n// PROFILES\n// Extends Supabase auth.users\n// Role determines which side of the app they see\n// ─────────────────────────────────────────\n\nmodel Profile {\n  id          String   @id @default(uuid())\n  roles       Role[]   @default([])\n  email       String   @unique\n  displayName String   @default(\"Unnamed User\")\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  rider  RiderProfile?\n  driver DriverProfile?\n\n  @@map(\"profiles\")\n}\n\nmodel RiderProfile {\n  id             String   @id @default(uuid())\n  profileId      String   @unique\n  homeLocationId String?  @db.Uuid\n  totalTrips     Int      @default(0)\n  createdAt      DateTime @default(now())\n\n  profile      Profile   @relation(fields: [profileId], references: [id], onDelete: Cascade)\n  homeLocation Location? @relation(fields: [homeLocationId], references: [id])\n  bookings     Booking[]\n\n  @@map(\"rider_profiles\")\n}\n\nmodel DriverProfile {\n  id         String       @id @default(uuid())\n  profileId  String       @unique\n  vesselName String // \"ISS Falcon-9B\"\n  vesselType VesselType\n  status     DriverStatus @default(OFFLINE)\n  rating     Float        @default(5.0)\n  totalTrips Int          @default(0)\n  createdAt  DateTime     @default(now())\n\n  profile  Profile   @relation(fields: [profileId], references: [id], onDelete: Cascade)\n  bookings Booking[]\n  earnings Earning[]\n\n  @@map(\"driver_profiles\")\n}\n\n// ─────────────────────────────────────────\n// LOCATIONS\n// Space stations, colonies, outposts\n// ─────────────────────────────────────────\n\nmodel Location {\n  id                String       @id @default(dbgenerated(\"gen_random_uuid()\")) @db.Uuid\n  name              String // \"Station Kepler-7\"\n  type              LocationType\n  description       String?\n  currentConditions String? // \"dust storm\", \"clear\", \"solar flare warning\"\n  travelTimes       Json         @default(\"{}\") // { \"<locationId>\": minutesInt }\n  isActive          Boolean      @default(true)\n  createdAt         DateTime     @default(now())\n\n  riderHomeLocations  RiderProfile[]\n  originBookings      Booking[]      @relation(\"OriginBookings\")\n  destinationBookings Booking[]      @relation(\"DestinationBookings\")\n\n  @@map(\"locations\")\n}\n\n// ─────────────────────────────────────────\n// BOOKINGS\n// Core table — one row per trip/delivery request\n// Mirrors an Uber trip request\n// ─────────────────────────────────────────\n\nmodel Booking {\n  id               String        @id @default(dbgenerated(\"gen_random_uuid()\")) @db.Uuid\n  riderId          String\n  driverId         String?\n  originId         String        @db.Uuid\n  destinationId    String        @db.Uuid\n  serviceType      ServiceType\n  status           BookingStatus @default(PENDING)\n  priceCredits     Int\n  departureTime    DateTime?\n  estimatedArrival DateTime?\n  actualArrival    DateTime?\n  aiBriefing       String? // Claude-generated travel briefing\n  cancelReason     String?\n  createdAt        DateTime      @default(now())\n  updatedAt        DateTime      @updatedAt\n\n  rider       RiderProfile   @relation(fields: [riderId], references: [id])\n  driver      DriverProfile? @relation(fields: [driverId], references: [id])\n  origin      Location       @relation(\"OriginBookings\", fields: [originId], references: [id])\n  destination Location       @relation(\"DestinationBookings\", fields: [destinationId], references: [id])\n  earning     Earning?\n\n  @@map(\"bookings\")\n}\n\n// ─────────────────────────────────────────\n// EARNINGS\n// One row per completed booking, on the driver side\n// Mirrors Uber's earnings/trips ledger\n// ─────────────────────────────────────────\n\nmodel Earning {\n  id           String   @id @default(uuid())\n  driverId     String\n  bookingId    String   @unique @db.Uuid\n  grossCredits Int // full fare\n  platformFee  Int // OrbitX cut (e.g. 25%)\n  netCredits   Int // what driver actually gets\n  createdAt    DateTime @default(now())\n\n  driver  DriverProfile @relation(fields: [driverId], references: [id])\n  booking Booking       @relation(fields: [bookingId], references: [id])\n\n  @@map(\"earnings\")\n}\n\n// ─────────────────────────────────────────\n// ENUMS\n// ─────────────────────────────────────────\n\nenum Role {\n  RIDER\n  DRIVER\n\n  @@map(\"role\")\n}\n\nenum DriverStatus {\n  OFFLINE\n  ONLINE\n  ON_TRIP\n\n  @@map(\"driver_status\")\n}\n\nenum VesselType {\n  SHUTTLE // passenger transport\n  FREIGHTER // cargo\n  COURIER // food/small deliveries\n\n  @@map(\"vessel_type\")\n}\n\nenum LocationType {\n  STATION\n  COLONY\n  OUTPOST\n\n  @@map(\"location_type\")\n}\n\nenum ServiceType {\n  SHUTTLE\n  CARGO\n  FOOD\n\n  @@map(\"service_type\")\n}\n\nenum BookingStatus {\n  PENDING // just created, awaiting driver\n  CONFIRMED // driver accepted\n  IN_TRANSIT // en route\n  DELIVERED // completed\n  CANCELLED // cancelled by either party\n\n  @@map(\"booking_status\")\n}\n",
